  phrases: [{ zh: "我要一杯咖啡。", es: "Quiero un café.", ipa: "/wo˨˩˦ yau˥˩ i˥ pei˥ kʰa˥ fei˥/" }, { zh: "请给我一杯水。", es: "Por favor, deme un vaso de agua.", ipa: "/ching˨˩˦ kei˨˩˦ wo˨˩˦ i˥ pei˥ shuei˨˩˦/" }, { zh: "我要热的。", es: "Lo quiero caliente.", ipa: "/wo˨˩˦ yau˥˩ re˥˩ de/" }, { zh: "不要糖。", es: "Sin azúcar.", ipa: "/pu˥˩ yau˥˩ tʰang˧˥/" }, { zh: "可以加牛奶吗？", es: "¿Puede añadir leche?", ipa: "/kʰɤ˨˩˦ i˨˩˦ chia˥ niou˧˥ nai˨˩˦ ma/" }, { zh: "我要小杯。", es: "Quiero tamaño pequeño.", ipa: "/wo˨˩˦ yau˥˩ shiau˨˩˦ pei˥/" }],
