  phrases: [{ zh: "我喜欢辣的。", es: "Me gusta lo picante.", ipa: "/wo˨˩˦ shi˨˩˦ xuan˥ la˥˩ de/" }, { zh: "我不吃辣。", es: "No como picante.", ipa: "/wo˨˩˦ pu˥˩ chʰɨ˥ la˥˩/" }, { zh: "一点辣可以。", es: "Un poco de picante está bien.", ipa: "/i˥ tien˨˩˦ la˥˩ kʰɤ˨˩˦ i˨˩˦/" }, { zh: "太辣了。", es: "Está demasiado picante.", ipa: "/tʰai˥˩ la˥˩ le/" }, { zh: "很好吃。", es: "Está muy rico.", ipa: "/xen˨˩˦ xau˨˩˦ chʰɨ˥/" }, { zh: "我对花生过敏。", es: "Soy alérgico/a al cacahuate.", ipa: "/wo˨˩˦ tuei˥˩ xua˥ sheng˥ kuo˥˩ min˨˩˦/" }],
