  phrases: [{ zh: "今天你有空吗？", es: "¿Tienes tiempo hoy?", ipa: "/chin˥ tʰien˥ ni˨˩˦ you˨˩˦ kʰong˥˩ ma/" }, { zh: "明天我们一起去。", es: "Mañana vamos juntos.", ipa: "/ming˧˥ tʰien˥ wo˨˩˦ men i˥ chi˨˩˦ chʰü˥/" }, { zh: "下午可以吗？", es: "¿Por la tarde está bien?", ipa: "/shia˥˩ wu˨˩˦ kʰɤ˨˩˦ i˨˩˦ ma/" }, { zh: "晚上见。", es: "Nos vemos por la noche.", ipa: "/wan˨˩˦ shang˥ chien˥˩/" }, { zh: "我想去公园。", es: "Quiero ir al parque.", ipa: "/wo˨˩˦ shiang˨˩˦ chʰü˥ kong˥ yuan˧˥/" }, { zh: "我们有什么计划？", es: "¿Qué plan tenemos?", ipa: "/wo˨˩˦ men you˨˩˦ shen˧˥ mɤ chi˥˩ xua˥˩/" }],
