var CONVERSATIONS_ES_ZH = [
{ title: "Pedir café en una cafetería de Hangzhou", scene: "Estás en una cafetería cerca del Lago del Oeste en Hangzhou. Quieres pedir una bebida caliente, confirmar si tiene leche y pagar con tarjeta.", lines: [{ who: "them", zh: "您好，想喝点什么？", es: "Hola, ¿qué le gustaría beber?" }, { who: "you", zh: "我要一杯热咖啡。", es: "Quiero un café caliente." }, { who: "them", zh: "大杯还是小杯？", es: "¿Grande o pequeño?" }, { who: "you", zh: "小杯，谢谢。", es: "Pequeño, gracias." }, { who: "them", zh: "要加糖吗？", es: "¿Quiere azúcar?" }, { who: "you", zh: "不要糖，可以加牛奶吗？", es: "Sin azúcar, ¿puede añadir leche?" }, { who: "them", zh: "可以。还要别的吗？", es: "Sí. ¿Quiere algo más?" }, { who: "you", zh: "请给我一杯水。", es: "Por favor, deme un vaso de agua." }, { who: "them", zh: "好的，一共三十元。", es: "Muy bien, son treinta yuanes en total." }, { who: "you", zh: "可以刷卡吗？", es: "¿Puedo pagar con tarjeta?" }, { who: "them", zh: "可以，请刷卡。", es: "Sí, pague con tarjeta, por favor." }, { who: "you", zh: "谢谢。", es: "Gracias." }] },
{ title: "Check-in en un hotel de Lijiang", scene: "Llegas por la tarde a un hotel en el casco antiguo de Lijiang. Tienes una reserva y necesitas preguntar por el wifi y el horario de salida.", lines: [{ who: "them", zh: "您好，欢迎光临。", es: "Hola, bienvenido/a." }, { who: "you", zh: "您好，我要入住。", es: "Hola, quiero hacer check-in." }, { who: "them", zh: "请问您有预订吗？", es: "¿Tiene una reserva?" }, { who: "you", zh: "我有预订，我叫安娜。", es: "Tengo una reserva, me llamo Ana." }, { who: "them", zh: "请给我您的护照。", es: "Por favor, deme su pasaporte." }, { who: "you", zh: "这是我的护照。", es: "Este es mi pasaporte." }, { who: "them", zh: "好的，您的房间在三楼。", es: "Muy bien, su habitación está en el tercer piso." }, { who: "you", zh: "房间有早餐吗？", es: "¿La habitación incluye desayuno?" }, { who: "them", zh: "有，早餐在早上七点到十点。", es: "Sí, el desayuno es de siete a diez de la mañana." }, { who: "you", zh: "无线网络密码是多少？", es: "¿Cuál es la contraseña del wifi?" }, { who: "them", zh: "密码在房卡上。", es: "La contraseña está en la tarjeta de la habitación." }, { who: "you", zh: "谢谢，几点退房？", es: "Gracias, ¿a qué hora es el check-out?" }] },
{ title: "Preguntar direcciones en Chengdu", scene: "Estás caminando por Chengdu y quieres llegar a una estación de metro cercana. Ves a una persona local y decides pedir ayuda de forma educada.", lines: [{ who: "you", zh: "请问，地铁站在哪里？", es: "Disculpe, ¿dónde está la estación de metro?" }, { who: "them", zh: "地铁站在前面。", es: "La estación de metro está adelante." }, { who: "you", zh: "远吗？", es: "¿Está lejos?" }, { who: "them", zh: "不远，走路五分钟。", es: "No está lejos, cinco minutos caminando." }, { who: "you", zh: "我要一直走吗？", es: "¿Debo seguir recto?" }, { who: "them", zh: "对，一直走，然后右转。", es: "Sí, siga recto y luego gire a la derecha." }, { who: "you", zh: "右边有入口吗？", es: "¿Hay una entrada a la derecha?" }, { who: "them", zh: "有，入口在商场旁边。", es: "Sí, la entrada está junto al centro comercial." }, { who: "you", zh: "谢谢你。", es: "Gracias." }, { who: "them", zh: "不客气。", es: "De nada." }, { who: "you", zh: "成都很好玩。", es: "Chengdu es muy divertido." }, { who: "them", zh: "欢迎你来成都。", es: "Bienvenido/a a Chengdu." }] },
{ title: "Comer en un restaurante de Xi’an", scene: "Entras a un restaurante de fideos en Xi’an. Quieres pedir algo no muy picante, preguntar por opciones vegetarianas y pedir la cuenta al final.", lines: [{ who: "them", zh: "您好，几位？", es: "Hola, ¿cuántas personas?" }, { who: "you", zh: "一个人。", es: "Una persona." }, { who: "them", zh: "请坐，这是菜单。", es: "Siéntese, este es el menú." }, { who: "you", zh: "谢谢，有素菜吗？", es: "Gracias, ¿hay platos vegetarianos?" }, { who: "them", zh: "有，这个是素面。", es: "Sí, estos son fideos vegetarianos." }, { who: "you", zh: "我要这个，不要辣。", es: "Quiero esto, sin picante." }, { who: "them", zh: "一点辣可以吗？", es: "¿Un poco de picante está bien?" }, { who: "you", zh: "可以，一点辣可以。", es: "Sí, un poco está bien." }, { who: "them", zh: "要喝什么？", es: "¿Qué quiere beber?" }, { who: "you", zh: "请给我一杯茶。", es: "Por favor, deme una taza de té." }, { who: "them", zh: "好的。", es: "Muy bien." }, { who: "you", zh: "买单，谢谢。", es: "La cuenta, gracias." }] },
{ title: "Comprar billete de metro en Nanjing", scene: "Estás en una estación de metro en Nanjing. Necesitas comprar un billete, confirmar la línea y encontrar la salida correcta.", lines: [{ who: "them", zh: "您好，需要帮助吗？", es: "Hola, ¿necesita ayuda?" }, { who: "you", zh: "我要买一张票。", es: "Quiero comprar un boleto." }, { who: "them", zh: "去哪里？", es: "¿A dónde va?" }, { who: "you", zh: "去南京南站。", es: "A la estación Nanjing Sur." }, { who: "them", zh: "请坐一号线。", es: "Tome la línea uno, por favor." }, { who: "you", zh: "这是几号线？", es: "¿Qué línea es esta?" }, { who: "them", zh: "这是二号线，要换乘。", es: "Esta es la línea dos, necesita transbordo." }, { who: "you", zh: "在哪里换乘？", es: "¿Dónde hago transbordo?" }, { who: "them", zh: "在新街口换乘。", es: "Haga transbordo en Xinjiekou." }, { who: "you", zh: "出口在哪里？", es: "¿Dónde está la salida?" }, { who: "them", zh: "出口在左边。", es: "La salida está a la izquierda." }, { who: "you", zh: "谢谢。", es: "Gracias." }] },
{ title: "Comprar recuerdos en un mercado de Suzhou", scene: "Estás en un mercado de Suzhou mirando recuerdos y seda. Quieres preguntar el precio, elegir un color y negociar un poco.", lines: [{ who: "them", zh: "您好，看看这个，很漂亮。", es: "Hola, mire esto, es muy bonito." }, { who: "you", zh: "这个多少钱？", es: "¿Cuánto cuesta esto?" }, { who: "them", zh: "一百二十元。", es: "Ciento veinte yuanes." }, { who: "you", zh: "太贵了。", es: "Es demasiado caro." }, { who: "them", zh: "这个质量很好。", es: "La calidad de esto es muy buena." }, { who: "you", zh: "可以便宜一点吗？", es: "¿Puede ser un poco más barato?" }, { who: "them", zh: "一百元，可以吗？", es: "Cien yuanes, ¿está bien?" }, { who: "you", zh: "有蓝色的吗？", es: "¿Tiene uno azul?" }, { who: "them", zh: "有，蓝色在这里。", es: "Sí, el azul está aquí." }, { who: "you", zh: "我要蓝色的。", es: "Quiero el azul." }, { who: "them", zh: "好的，您怎么付款？", es: "Muy bien, ¿cómo paga?" }, { who: "you", zh: "我用现金。", es: "Pago en efectivo." }] },
{ title: "En una farmacia de Tianjin", scene: "Te sientes mal durante un viaje en Tianjin y entras a una farmacia. Necesitas explicar síntomas simples y preguntar si hay un hospital cerca.", lines: [{ who: "them", zh: "您好，需要什么？", es: "Hola, ¿qué necesita?" }, { who: "you", zh: "我需要药。", es: "Necesito medicina." }, { who: "them", zh: "您哪里不舒服？", es: "¿Dónde se siente mal?" }, { who: "you", zh: "我头疼，也有点感冒。", es: "Me duele la cabeza y estoy un poco resfriado/a." }, { who: "them", zh: "有发烧吗？", es: "¿Tiene fiebre?" }, { who: "you", zh: "没有发烧。", es: "No tengo fiebre." }, { who: "them", zh: "这个药可以。", es: "Esta medicina sirve." }, { who: "you", zh: "怎么吃？", es: "¿Cómo se toma?" }, { who: "them", zh: "一天三次，饭后吃。", es: "Tres veces al día, después de comer." }, { who: "you", zh: "附近有医院吗？", es: "¿Hay un hospital cerca?" }, { who: "them", zh: "有，医院在前面。", es: "Sí, el hospital está adelante." }, { who: "you", zh: "谢谢你的帮助。", es: "Gracias por su ayuda." }] },
{ title: "Charla casual con una persona local en Tainan", scene: "Estás en una cafetería tranquila en Tainan y una persona local empieza una conversación amistosa. Practicas tu chino con frases simples sobre origen, viajes y gustos.", lines: [{ who: "you", zh: "你好，这里有人吗？", es: "Hola, ¿hay alguien aquí?" }, { who: "them", zh: "没有，请坐。", es: "No, siéntate por favor." }, { who: "you", zh: "谢谢，我来自西班牙。", es: "Gracias, vengo de España." }, { who: "them", zh: "欢迎，你喜欢台南吗？", es: "Bienvenido/a, ¿te gusta Tainan?" }, { who: "you", zh: "喜欢，这里很好玩。", es: "Sí, este lugar es muy divertido." }, { who: "them", zh: "你喜欢什么食物？", es: "¿Qué comida te gusta?" }, { who: "you", zh: "我喜欢面条，也喜欢茶。", es: "Me gustan los fideos y también el té." }, { who: "them", zh: "你会说中文，说得不错。", es: "Sabes hablar chino, lo hablas bastante bien." }, { who: "you", zh: "谢谢，我还在学习。", es: "Gracias, todavía estoy aprendiendo." }, { who: "them", zh: "明天有什么计划？", es: "¿Qué planes tienes mañana?" }, { who: "you", zh: "我想去博物馆和海边。", es: "Quiero ir al museo y a la costa." }, { who: "them", zh: "很好，祝你玩得开心。", es: "Muy bien, espero que te diviertas." }] }
];
